import {color} from '@heroku-cli/color'
import {Command, flags} from '@heroku-cli/command'
import {ux} from '@oclif/core'

import confirmCommand from '../../../lib/confirm-command'

import util = require('util')

const confirmMsg = 'WARNING: This will delete the build cache for %s.\nClearing your build cache can have unintended side effects, such as updating your language version if you don\'t explicitly specify one.'
export default class Purge extends Command {
  static description = 'purge the build cache for the specified app'
  static flags = {
    confirm: flags.string({char: 'c'}),
    app: flags.app({required: true}),
    remote: flags.remote(),
  }

  static topic = 'builds'

  public async run(): Promise<void> {
    const {flags} = await this.parse(Purge)
    const {app, confirm} = flags
    await confirmCommand(app, confirm, util.format(confirmMsg, color.magenta(app)))
    ux.action.start(`Purging build cache for ${color.magenta(app)}`)
    try {
      await this.heroku.delete(`/apps/${app}/build-cache`)
    } catch (error) {
      const {name} = error as Error
      // These occur with 202's from this endpoint for some reason.
      if (name !== 'SyntaxError') {
        throw error
      }
    }

    ux.action.stop()
  }
}

import {color} from '@heroku-cli/color'
import {ux} from '@oclif/core'

export default async function confirmCommand(app: string, confirm?: string, message?: string) {
  if (confirm) {
    if (confirm === app) return
    throw new Error(`Confirmation ${color.bold.red(confirm)} did not match ${color.bold.red(app)}. Aborted.`)
  }

  if (!message) {
    message = `WARNING: Destructive Action
This command will affect the app ${color.bold.red(app)}`
  }

  ux.warn(message)
  console.error()
  const entered = await ux.prompt(
    `To proceed, type ${color.bold.red(app)} or re-run this command with ${color.bold.red('--confirm', app)}`,
    {required: true},
  )
  if (entered === app) {
    return
  }

  throw new Error(`Confirmation did not match ${color.bold.red(app)}. Aborted.`)
}

import {color} from '@heroku-cli/color'
import {Command, flags} from '@heroku-cli/command'
import {Args, ux} from '@oclif/core'

import {findByLatestOrId} from '../../lib/builds'

export default class Cancel extends Command {
  static args = {
    build: Args.string(),
  }

  static description = 'cancel a running build\nStops executing a running build. Omit BUILD to cancel the latest build.'
  static flags = {
    app: flags.app({required: true}),
  }

  static topic = 'builds'

  public async run(): Promise<void> {
    const {flags, args} = await this.parse(Cancel)
    const {app} = flags
    const {build: buildId} = args
    const build = await findByLatestOrId(this.heroku, app, buildId)
    if (!build) {
      return ux.warn(`No build found for: ${buildId || app}`)
    }

    if (build.status !== 'pending') {
      return ux.error(`Can only cancel pending builds. Build ${build.id} has status '${build.status}'`)
    }

    ux.action.start(`Stopping build ${build.id}`)
    await this.heroku.delete(`/apps/${app}/builds/${build.id}`, {
      headers: {Accept: 'application/vnd.heroku+json; version=3.cancel-build'},
    })
    ux.action.stop()
  }
}

import {APIClient} from '@heroku-cli/command'
import * as Heroku from '@heroku-cli/schema'

export async function findBuild(heroku: APIClient, app: string, search: (builds: Heroku.Build[]) => Heroku.Build): Promise<Heroku.Build | undefined> {
  const {body: builds} = await heroku.get<Heroku.Build[]>(`/apps/${app}/builds`, {
    partial: true,
    headers: {Range: 'created_at ..; max=10, order=desc'}
  })
  return search(builds)
}

export async function findByLatestOrId(heroku: APIClient, app: string, build: string | undefined): Promise<Heroku.Build | undefined> {
  if (!build) {
    return findBuild(heroku, app, builds => builds[0])
  }

  const {body} = await heroku.get<Required<Heroku.Build>>(`/apps/${app}/builds/${build}`)
  return body
}

export function statusColor(status: Heroku.Build['status']) {
  switch (status) {
  case 'pending': {
    return 'yellow'
  }

  case 'failed': {
    return 'red'
  }

  case 'succeeded': {
    return 'green'
  }

  default: {
    return 'white'
  }
  }
}

import {APIClient, Command, flags} from '@heroku-cli/command'
import * as Heroku from '@heroku-cli/schema'
import {ux} from '@oclif/core'
import HTTP from '@heroku/http-call'
import {exec} from 'node:child_process'
import {randomUUID} from 'node:crypto'
import {createReadStream, statSync} from 'node:fs'
import {stat} from 'node:fs/promises'
import * as os from 'node:os'
import * as path from 'node:path'
import {promisify} from 'node:util'

import {nodeTar} from '../../lib/node-tar'

const execPromisified = promisify(exec)

async function compressSource(tar: string, includeVcsIgnore: boolean, dir: string, tempFile: string) {
  let tarVersion = ''
  try {
    const result = await execPromisified(tar + ' --version')
    tarVersion = result.stdout
  } catch (error) {
    const {message} = error as Error
    if (!/not found/.test(message)) {
      throw error
    }
  }

  if (/GNU tar/.test(tarVersion)) {
    let command = tar + ' cz -C ' + dir
    if (!includeVcsIgnore) {
      command += ' --exclude-vcs-ignores'
    }

    command += ' --exclude .git --exclude .gitmodules'
    command += ' .'
    await execPromisified(command + ' > ' + tempFile)
  } else {
    ux.warn('Couldn\'t detect GNU tar. Builds could fail due to decompression errors')
    ux.warn('See https://devcenter.heroku.com/articles/platform-api-deploying-slugs#create-slug-archive')
    ux.warn('Please install it, or specify the \'--tar\' option')
    ux.warn('Falling back to node\'s built-in compressor')
    await nodeTar(dir, tempFile)
  }
}

async function uploadDirToSource(tar: string | undefined, includeVcsIgnore: boolean, heroku: APIClient, tarPath: string) {
  let filePath
  const tarPathStat = await stat(tarPath)
  if (tarPathStat.isDirectory()) {
    filePath = path.join(os.tmpdir(), randomUUID() + '.tar.gz')
    await compressSource((tar ?? 'tar'), includeVcsIgnore, tarPath, filePath)
  } else {
    filePath = tarPath
  }

  const {body: source} = await heroku.post<Required<Heroku.Source>>('/sources')

  await HTTP.put(source.source_blob.put_url as string, {
    body: createReadStream(filePath),
    headers: {
      'Content-Type': '',
      'Content-Length': statSync(filePath).size,
    }
  })
  return source.source_blob.get_url
}

export default class Create extends Command {
  static description = 'create build\nCreate build from contents of current dir'
  static flags = {
    'source-tar': flags.string({description: 'local path to source to the tarball of your application\'s source code'}),
    'source-url': flags.string({description: 'source URL that points to the tarball of your application\'s source code'}),
    dir: flags.string({description: 'the local path to build. Defaults to the current working directory'}),
    tar: flags.string({description: 'path to the executable GNU tar'}),
    version: flags.string({description: 'description of your new build'}),
    'include-vcs-ignore': flags.boolean({description: 'include files ignored by VCS (.gitignore, ...) from the build'}),
    app: flags.app({required: true}),
    remote: flags.remote(),
  }

  static topic = 'builds'

  public async run(): Promise<void> {
    const {flags} = await this.parse(Create)
    const {
      app,
      dir = process.cwd(),
      tar,
      'include-vs-ignore': includeVcsIgnore,
      'source-tar': sourceTar,
      'source-url': sourceUrl,
      version,
    } = flags
    let targetSourceUrl = sourceUrl
    if (sourceTar) {
      targetSourceUrl = await uploadDirToSource(tar, includeVcsIgnore, this.heroku, sourceTar)
    } else if (!sourceUrl) {
      targetSourceUrl = await uploadDirToSource(tar, includeVcsIgnore, this.heroku, dir)
    }

    const {body: newBuild} = await this.heroku.post<Required<Heroku.Build>>(`/apps/${app}/builds`, {
      body: {
        source_blob: {
          url: targetSourceUrl,
          version: version || '',
        },
      },
    })
    const {response: stream} = await this.heroku.stream(newBuild.output_stream_url)
    await new Promise((resolve, reject) => {
      stream.on('error', reject)
      stream.on('end', resolve)
      stream.pipe(process.stderr)
    })
    const {body: build} = await this.heroku.get<Heroku.Build>(`/apps/${app}/builds/${newBuild.id}`)
    if (build.status === 'failed') {
      ux.error('Build failed', {exit: 1})
    }
  }
}

import ignore from 'ignore'
import * as fs from 'node:fs'
import {readdir} from 'node:fs/promises'
import * as os from 'node:os'
import {create} from 'tar'

export async function nodeTar(cwd: string, file: string): Promise<void> {
  let ig = ignore()
  if (fs.existsSync('./.gitignore')) {
    ig = ig.add(fs.readFileSync('./.gitignore').toString())
  }

  const filter = ig.createFilter()
  const files = await readdir(cwd)
  await create({
    gzip: true,
    file,
    cwd,
    filter,
    mode: os.platform() === 'win32' ? 0o0755 : 0o666,
  }, files)
}

import {color} from '@heroku-cli/color'
import {Command, flags} from '@heroku-cli/command'
import * as Heroku from '@heroku-cli/schema'
import {ux} from '@oclif/core'

import {statusColor} from '../../lib/builds'
import {ago, duration} from '../../lib/time'

export default class Index extends Command {
  static description = 'list builds\nList builds for a Heroku app'
  static flags = {
    num: flags.string({char: 'n', description: 'number of builds to show'}),
    app: flags.app({required: true}),
    remote: flags.remote(),
  }

  static topic = 'builds'

  public async run(): Promise<void> {
    const {flags} = await this.parse(Index)
    const {app, num} = flags
    const {body: builds} = await this.heroku.get<Heroku.Build[]>(`/apps/${app}/builds`, {
      partial: true,
      headers: {Range: `created_at ..; max=${num || 15}, order=desc`},
    })
    ux.styledHeader(`${app} Builds`)
    ux.table<Heroku.Build>(builds, {
      id: {
        header: 'ID',
        get(row: Heroku.Build): null | string | undefined {
          return row.id
        },
      },
      sourceVersion: {
        header: 'Source Version',
        get(row: Heroku.Build): null | string | undefined {
          return row.source_blob?.version
        }
      },
      created_at: {
        header: 'Created At',
        get(row: Heroku.Build): null | string | undefined {
          return ago(new Date(row.created_at as string))
        },
      },
      duration: {
        header: 'Duration',
        get(row: Heroku.Build): null | string | undefined {
          return duration(new Date(row.created_at as string), new Date(row.updated_at as string))
        }
      },
      status: {
        header: 'Status',
        get(row: Heroku.Build): null | string | undefined {
          return color[statusColor(row.status)](row.status)
        }
      },
      user: {
        header: 'User',
        get(row: Heroku.Build): null | string | undefined {
          return color.magenta(row.user?.email?.replace(/@addons\.heroku\.com$/, ''))
        }
      }
    },
    {
      'no-truncate': true,
    })
  }
}

import strftime from 'strftime'

export function ago(since: Date) {
  const elapsed = Math.floor((Date.now() - since.getTime()) / 1000)
  const message = strftime('%Y/%m/%d %H:%M:%S %z', since)
  if (elapsed < 60) return `${message} (~ ${Math.floor(elapsed)}s ago)`
  if (elapsed < 60 * 60) return `${message} (~ ${Math.floor(elapsed / 60)}m ago)`
  if (elapsed < 60 * 60 * 25) return `${message} (~ ${Math.floor(elapsed / 60 / 60)}h ago)`
  return message
}

export function duration(from: Date, to: Date) {
  const secs = Math.floor((to.getTime() / 1000) - (from.getTime() / 1000))
  const mins = Math.floor(secs / 60)
  const hours = Math.floor(mins / 60)
  if (hours > 0) return `${hours}h ${mins % 60}m`
  if (mins > 0) return `${mins}m ${secs % 60}s`
  if (secs > 0) return `${secs}s`
  return ''
}

import color from '@heroku-cli/color'
import {Command, flags} from '@heroku-cli/command'
import * as Heroku from '@heroku-cli/schema'
import {Args, ux} from '@oclif/core'

import {findByLatestOrId, statusColor} from '../../lib/builds'

export default class Info extends Command {
  static args = {
    build: Args.string(),
  }

  static description = 'view detailed information for a build'
  static flags = {
    json: flags.boolean({description: 'output in json format'}),
    app: flags.app({required: true}),
    remote: flags.remote()
  }

  static topic = 'builds'

  public async run(): Promise<void> {
    const {flags, args} = await this.parse(Info)
    const {app, json} = flags
    const build = await findByLatestOrId(this.heroku, app, args.build)
    if (!build) {
      return ux.warn(`No builds found for ${args.build || app}`)
    }

    if (json) {
      ux.styledJSON(build)
    } else {
      ux.styledHeader(`Build ${color[statusColor(build.status)](build.id)}`)
      const data = {
        By: build.user?.email,
        When: build.created_at,
        Status: build.status,
        Buildpacks: build.buildpacks?.map(e => e.url),
      } as Record<string, unknown>

      if (build.release) {
        const {body: release} = await this.heroku.get<Heroku.Release>(`/apps/${app}/releases/${build.release.id}`)
        data.Release = `v${release.version}`
      }

      ux.styledObject(data)
    }
  }
}

import {Command, flags} from '@heroku-cli/command'
import {Args, ux} from '@oclif/core'

import {findByLatestOrId} from '../../lib/builds'

export default class Output extends Command {
  static args = {
    build: Args.string(),
  }

  static description = 'show build output. Omit BUILD to get latest build.\nShow build output for a Heroku app. Omit BUILD to get the output for the latest build.'
  static flags = {
    app: flags.app({required: true}),
    remote: flags.remote()
  }

  static topic = 'builds'

  public async run(): Promise<void> {
    const {flags, args} = await this.parse(Output)
    const {app} = flags
    const build = await findByLatestOrId(this.heroku, app, args.build)
    if (!build) {
      return ux.warn(`No build found for ${args.build || app}.`)
    }

    const {response: stream} = await this.heroku.stream(build.output_stream_url as string)
    return new Promise((resolve, reject) => {
      stream.on('error', reject)
      stream.on('end', resolve)
      stream.pipe(process.stdout)
    })
  }
}
